    if( p[j] == '*' and dp[i][j-2] == 1 ) {
        return true;
    }
    return false;
}
bool isMatch(string s, string p) {
    for(int i=0;i<25;i++) for(int j=0;j<25;j++) dp[i][j] = 0;
    dp[0][0] = 1;
    s = "#"+s;
    p = "#"+p;
