vector<int> solve(int n) {
    vector<int> primes;
    for(int i=2;i<=n;i++){
        bool isPrime = true;
        for(int j=2;j<i;j++) {
            if( i%j == 0 ) isPrime = false;
        }
        if( isPrime ) primes.push_back(i);
    }
