```C++ [O(n logn)]
vector<int> solve(int n) {
    bool notPrime[n+1] = {0};
    vector<int> primes;
    for(int i=2;i<=n;i++){
        if( notPrime[i] == true ) continue;
        primes.push_back(i);
        for(int j=i*i;j<=n;j+=i) notPrime[j] = true;
    }
    return primes;
}
