```C++
bool isValid(string s) {
    stack<char> st;
    for(auto c:s){
        if( c == '(' or c == '[' or c == '{' ) {
            st.push(c);
            continue;
        }
        if( !st.size() ) return false;
        if( c == ')' ) {
            if(  st.top() != '(' ) return false;
        }else if(  c == '}' ) {
            if( st.top() != '{' ) return false;
        } else if( c == ']' ) {
            if( st.top() != '[' ) return false;
        }
        st.pop();
    }
    return st.size() == 0;
}
